import{c as e}from"./api-RY2-2DBj.js";const n={getAll(){return e.get("/contracts")},getById(t){return e.get(`/contracts/${t}`)},getByStudentId(t){return e.get(`/contracts/student/${t}`)},getByUserId(t){return e.get(`/contracts/user/${t}`)},getByStatus(t){return e.get(`/contracts/status/${t}`)},getByContractCode(t){return e.get(`/contracts/code/${t}`)},create(t){return e.post("/contracts",t)},update(t,r){return e.put(`/contracts/${t}`,r)},activate(t){return e.put(`/contracts/${t}/activate`)},acceptContract(t,r){return e.post(`/contracts/${t}/accept`,r)},terminate(t,r){return e.put(`/contracts/${t}/terminate`,r)},delete(t){return e.delete(`/contracts/${t}`)}};export{n as c};
